package cache

import (
	"encoding/json"
	"os"
	"testing"
	"time"
)

func TestStoreSetUsesPrivatePermissions(t *testing.T) {
	dir := t.TempDir() + "/cache"
	store := New(dir, time.Minute)

	store.Set("shops", json.RawMessage(`{"token":"redacted"}`))

	dirInfo, err := os.Stat(dir)
	if err != nil {
		t.Fatalf("cache dir stat failed: %v", err)
	}
	if got, want := dirInfo.Mode().Perm(), os.FileMode(0o700); got != want {
		t.Fatalf("cache dir mode = %v, want %v", got, want)
	}

	fileInfo, err := os.Stat(store.path("shops"))
	if err != nil {
		t.Fatalf("cache file stat failed: %v", err)
	}
	if got, want := fileInfo.Mode().Perm(), os.FileMode(0o600); got != want {
		t.Fatalf("cache file mode = %v, want %v", got, want)
	}
}
